public static void main(Args args)
{
    var builder = DBMSQLQueryStoreRuntimeStatsIntervalViewBuilder::construct();
    builder.createSqlObjects();
}

private str createViewSqlStmt()
{
    str sqlStmt = 'CREATE VIEW ' + viewName + ' AS ' + this.createSQLStatement();
    return sqlStmt;
}

protected void initialize(boolean _runOnSeparateUserConnection = false)
{
    super(_runOnSeparateUserConnection);

    SysDictView view    = new SysDictView(tableNum(DBMSQLQueryStoreRuntimeStatsInterval));
    viewName            = view.name(DbBackend::Sql);
    asRuntimeStatsIntervalId = view.fieldObject(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, RuntimeStatsIntervalId)).name(DbBackend::Sql);
    asStartTime = view.fieldObject(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, StartTime)).name(DbBackend::Sql);
    asEndTime = view.fieldObject(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, EndTime)).name(DbBackend::Sql);
    asComment = view.fieldObject(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, Comment)).name(DbBackend::Sql);
    asTime = view.fieldObject(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, Time)).name(DbBackend::Sql);
    asHour = view.fieldObject(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, Hour)).name(DbBackend::Sql);
    asDay = view.fieldObject(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, Day)).name(DbBackend::Sql);
    asWeek = view.fieldObject(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, Week)).name(DbBackend::Sql);
    asMonth = view.fieldObject(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, Month)).name(DbBackend::Sql);
    asRecId = view.fieldObject(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, RecId)).name(DbBackend::Sql);

}
